sql:
SELECT MAX(usage_count) AS highest_usage_count
FROM word_usage
WHERE experiment_id = 1;

SELECT word_id
FROM word_usage
WHERE usage_count = (SELECT MAX(usage_count) FROM word_usage);

SELECT word_id, SUM(usage_count) AS total_usage_count, MAX(last_used) AS last_used_date
FROM word_usage
GROUP BY word_id;

SELECT COUNT(*) 
FROM words 
WHERE set_id = (SELECT set_id FROM sets WHERE set_name = 'Positive Words');

